// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

interface IERC20 { function balanceOf(address) external view returns (uint256); }

contract SpotPriceOracle {
    address public token;
    address public weth;

    constructor(address _token, address _weth) {
        token = _token;
        weth = _weth;
    }

    function getPrice() public view returns (uint256) {
        uint256 tokenBal = IERC20(token).balanceOf(address(this));
        uint256 wethBal = IERC20(weth).balanceOf(address(this));
        require(tokenBal > 0, 'no liquidity');
        return wethBal * 1e18 / tokenBal;
    }

    function borrow(uint256 amount) external {
        uint256 price = getPrice();
        uint256 collateralRequired = amount * price / 1e18;
        // transfer collateral check omitted for brevity
        require(collateralRequired > 0, 'bad price');
    }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract LendingPool {
    uint256 public totalBorrows;
    uint256 public borrowIndex = 1e18;

    mapping(address => uint256) public borrowShares;

    function borrow(uint256 amount) external {
        uint256 shares = amount / borrowIndex;
        borrowShares[msg.sender] += shares;
        totalBorrows += amount;
    }

    function repay(address borrower) external payable {
        uint256 owed = borrowShares[borrower] * borrowIndex;
        require(msg.value >= owed, 'insufficient');
        delete borrowShares[borrower];
        totalBorrows -= owed;
    }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

interface IToken {
    function transfer(address to, uint256 amount) external returns (bool);
}

contract Vault {
    mapping(address => uint256) public balances;
    IToken public token;

    constructor(address _token) { token = _token; }

    function deposit(uint256 amount) external {
        balances[msg.sender] += amount;
    }

    function withdraw(uint256 amount) external {
        require(balances[msg.sender] >= amount, 'insufficient');
        token.transfer(msg.sender, amount);
        balances[msg.sender] -= amount;
    }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract FeeCollector {
    address public treasury;
    uint256 public feeBps = 30;

    constructor(address _treasury) {
        treasury = _treasury;
    }

    function setFeeBps(uint256 newFee) external {
        require(newFee <= 1000, 'fee too high');
        feeBps = newFee;
    }

    function setTreasury(address newTreasury) external {
        treasury = newTreasury;
    }

    function collectFee(uint256 amount) external returns (uint256 fee) {
        fee = amount * feeBps / 10000;
    }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

interface IERC20 {
    function transferFrom(address, address, uint256) external returns (bool);
    function transfer(address, uint256) external returns (bool);
    function balanceOf(address) external view returns (uint256);
}

contract SimpleVault {
    IERC20 public asset;
    uint256 public totalShares;

    constructor(address _asset) { asset = _asset; }

    function deposit(uint256 assets) external returns (uint256 shares) {
        uint256 supply = totalShares;
        uint256 totalAssets = asset.balanceOf(address(this));
        shares = supply == 0 ? assets : assets * supply / totalAssets;
        totalShares += shares;
        asset.transferFrom(msg.sender, address(this), assets);
    }

    function redeem(uint256 shares) external returns (uint256 assets) {
        assets = shares * asset.balanceOf(address(this)) / totalShares;
        totalShares -= shares;
        asset.transfer(msg.sender, assets);
    }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import '@openzeppelin/contracts/access/Ownable.sol';

contract StableLending is Ownable {
    mapping(address => uint256) public collateral;
    mapping(address => uint256) public debt;
    uint256 public constant COLLATERAL_FACTOR = 150;

    function depositCollateral(uint256 amount) external {
        collateral[msg.sender] += amount;
    }

    function borrow(uint256 amount) external {
        uint256 maxBorrow = collateral[msg.sender] * 100 / COLLATERAL_FACTOR;
        require(debt[msg.sender] + amount <= maxBorrow, 'undercollateralized');
        debt[msg.sender] += amount;
    }

    function repay(uint256 amount) external {
        require(debt[msg.sender] >= amount, 'overpay');
        debt[msg.sender] -= amount;
    }

    function withdrawCollateral(uint256 amount) external {
        uint256 remaining = collateral[msg.sender] - amount;
        uint256 maxBorrow = remaining * 100 / COLLATERAL_FACTOR;
        require(debt[msg.sender] <= maxBorrow, 'would undercollateralize');
        collateral[msg.sender] = remaining;
    }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract StakingRewards {
    mapping(address => uint256) public staked;
    mapping(address => uint256) public rewardDebt;
    uint256 public accRewardPerShare;
    uint256 public totalStaked;

    function stake(uint256 amount) external {
        totalStaked += amount;
        staked[msg.sender] += amount;
    }

    function distributeRewards(uint256 rewardAmount) external {
        if (totalStaked > 0) {
            accRewardPerShare += rewardAmount * 1e12 / totalStaked;
        }
    }

    function harvest() external returns (uint256 reward) {
        reward = staked[msg.sender] * accRewardPerShare / 1e12 - rewardDebt[msg.sender];
        rewardDebt[msg.sender] = staked[msg.sender] * accRewardPerShare / 1e12;
    }

    function unstake(uint256 amount) external {
        require(staked[msg.sender] >= amount, 'insufficient');
        harvest();
        staked[msg.sender] -= amount;
        totalStaked -= amount;
    }
}

