// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract NFTAuction {
    struct Auction {
        address highestBidder;
        uint256 highestBid;
        uint256 endTime;
        bool settled;
    }

    mapping(uint256 => Auction) public auctions;
    mapping(address => uint256) public pendingReturns;

    function bid(uint256 auctionId) external payable {
        Auction storage a = auctions[auctionId];
        require(block.timestamp < a.endTime, 'ended');
        require(msg.value > a.highestBid, 'too low');
        pendingReturns[a.highestBidder] += a.highestBid;
        a.highestBidder = msg.sender;
        a.highestBid = msg.value;
    }

    function withdraw() external {
        uint256 amount = pendingReturns[msg.sender];
        pendingReturns[msg.sender] = 0;
        payable(msg.sender).transfer(amount);
    }

    function settle(uint256 auctionId) external {
        Auction storage a = auctions[auctionId];
        require(block.timestamp >= a.endTime, 'not ended');
        require(!a.settled, 'settled');
        a.settled = true;
    }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract BondMarket {
    struct Market {
        address owner;
        uint256 price;
        uint256 discountBps;
        uint256 sold;
        uint256 capacity;
    }

    mapping(uint256 => Market) public markets;
    uint256 public nextId;

    function createMarket(
        uint256 price,
        uint256 discountBps,
        uint256 capacity
    ) external returns (uint256 id) {
        id = nextId++;
        markets[id] = Market(msg.sender, price, discountBps, 0, capacity);
    }

    function purchase(uint256 marketId, uint256 amount) external payable {
        Market storage m = markets[marketId];
        require(m.sold + amount <= m.capacity, 'sold out');
        uint256 effectivePrice = m.price * (10000 - m.discountBps) / 10000;
        require(msg.value >= effectivePrice * amount, 'insufficient payment');
        m.sold += amount;
    }
}
